import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  Outlet
} from "react-router-dom";
import { useState, createContext, useContext } from "react";

const AuthContext = createContext();

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(
    JSON.parse(localStorage.getItem("user")) || null
  );

  const login = (data) => {
    localStorage.setItem("user", JSON.stringify(data));
    setUser(data);
  };

  const logout = () => {
    localStorage.removeItem("user");
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

const useAuth = () => useContext(AuthContext);

const ProtectedRoute = ({ role }) => {
  const { user } = useAuth();

  if (!user) return <Navigate to="/login" />;
  if (role && user.role !== role) return <Navigate to="/" />;

  return <Outlet />;
};

const Home = () => {
  const { user } = useAuth();

  return (
    <>
      <nav className="navbar">
        <a className="nav-title">Home Page</a>

        {!user && (
          <button onClick={() => (window.location.href = "/login")}>
            Login / Register
          </button>
        )}

        {user && user.role === "client" && (
          <button onClick={() => (window.location.href = "/client")}>
            Client Dashboard
          </button>
        )}

        {user && user.role === "tasker" && (
          <button onClick={() => (window.location.href = "/tasker")}>
            Tasker Dashboard
          </button>
        )}

        {user && user.role === "admin" && (
          <button onClick={() => (window.location.href = "/admin")}>
            Admin Dashboard
          </button>
        )}
      </nav>



      <div className="back">
        <section className="hero">
          <h1>Book trusted help for home tasks</h1>
        </section>

      <div className="search">
        <input placeholder="Search tasks..." />
        <button>Search</button>
      </div>
      </div>

      <div className="empty"></div>

      <div style={{display:" grid", gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))"}} className="houseservices">
        <div className="serviceitem">
          <img src="cleaning.png" alt="" />
          <h2>Cleaning</h2>
          <p>Daily or weekly cleaning services for your home.</p>
        </div>

        <div className="serviceitem">
          <img src="car-repair.jpg" alt="" />
          <h2> Car Repairs</h2>
          <p>Handyman services for repairs and maintenance.</p>
        </div>

        <div className="serviceitem">
          <img src="gardening.jpg" alt="" />
          <h2>Gardening</h2>
          <p>Lawn care and gardening services.</p>
        </div>

        <div className="serviceitem">
          <img src="carpentry.png" alt="" />
          <h2>Carpentry</h2>
          <p>Custom carpentry and woodworking services.</p>
        </div>

        <div className="serviceitem">
          <img src="cooking.png" alt="" />
          <h2>Cooking</h2>
          <p>Private chef or meal preparation services.</p>
        </div>

        <div className="serviceitem">
          <img src="painting.png" alt="" />
          <h2>Painting</h2>
          <p>Interior and exterior painting services.</p>
        </div>

        <div className="serviceitem">
          <img src="Plumbing.jpg" alt="" />
          <h2>Plumbing</h2>
          <p>Plumbing repairs and installations.</p>
        </div>

        <div className="serviceitem">
          <img src="electricity.jpg" alt="" />
          <h2>Electrical</h2>
          <p>Electrical repairs and installations.</p>
        </div>

        <div className="serviceitem">
          <img src="carwash.jpeg" alt="" />
          <h2>Car Wash</h2>
          <p>Mobile car wash and detailing services.</p>
        </div>

        <div className="serviceitem">
          <img src="event planning.jpg" alt="" />
          <h2>Event Planning</h2>
          <p>Full-service event planning and coordination.</p>
        </div>

        <div className="serviceitem">
          <img src="pest-control.jpeg" alt="" />
          <h2>Pest Control</h2>
          <p>Pest removal and prevention services.</p>
        </div>
                <div className="serviceitem">
          <img src="pest-control.jpeg" alt="" />
          <h2>Browse More Services</h2>
          <p>Pest removal and prevention services.</p>
        </div>
      </div>

      <div className="container">
        <h1>Your Satisfaction, Guaranteed</h1>

        <div className="headings">
          <h2>
            Happiness Pledge
            <p>If you're not satisfied, we'll work to make it right.</p>
          </h2>

          <h2>
            Vetted Taskers
            <p>
              Taskers are always background checked before joining the platform.
            </p>
          </h2>

          <h2>
            Dedicated Support
            <p>
              Friendly service when you need us - every day of the week.
            </p>
          </h2>
        </div>
      </div>

      <div className="working">
        <div className="bg">
          <div className="picture">
            <img src="how.jpg" alt="" />
          </div>

          <div id="howitworks">
            <h2>How it works</h2>
            <ol>
              <li>
                <h3>Choose a Tasker</h3>
                <p>
                  Browse our marketplace of skilled Taskers and choose the one
                  that fits your needs and budget.
                </p>
              </li>

              <li>
                <h3>Schedule a Tasker</h3>
                <p>Schedule your Tasker for a time that works for you.</p>
              </li>

              <li>
                <h3>Chat, Pay, and Review</h3>
                <p>Chat with your Tasker, pay, and review in one place.</p>
              </li>
            </ol>
          </div>
        </div>
      </div>

      <div id="help">
        <h2>Get Help Today</h2>
      </div>

      <div className="serve">
        <button onClick={() => (window.location.href = "/Tasks")}>Cleaning</button>
        <button onClick={() => (window.location.href = "/Tasks")}>Plumbing Help</button>
        <button onClick={() => (window.location.href = "/Tasks")}>Gardening Services</button>
        <button onClick={() => (window.location.href = "/Tasks")}>Woodworking services</button>
        <button onClick={() => (window.location.href = "/electrical")}>Electrical repairs</button>
        <button onClick={() => (window.location.href = "/Tasks")}>AutoMobile car wash</button>
        <button onClick={() => (window.location.href = "/Tasks")}>Pest removal</button>
        <button onClick={() => (window.location.href = "/Tasks")}>Event planning</button>
        <button onClick={() => (window.location.href = "/Tasks")}>Cooking</button>
        <button onClick={() => (window.location.href = "/Tasks")}>Car repairs</button>
        <button onClick={() => (window.location.href = "/Tasks")}>House Painting</button>
      </div>
    </>
  );
};



function Login() {
  const { login } = useAuth();
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("client");

  const handleLogin = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/auth/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ email, password }),
      });

      const data = await res.json();

      if (res.ok) {
        // store role also (important)
        login({ ...data, email, role });

        // redirect based on role
        if (role === "client") navigate("/client");
        else if (role === "tasker") navigate("/tasker");
        else navigate("/admin");
      } else {
        alert(data.message);
      }
    } catch (err) {
      alert("Error logging in");
    }
  };

  return (
    <div>
      <h2>Login</h2>

      <input
        type="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)} />

      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)} />

      <select value={role} onChange={(e) => setRole(e.target.value)}>
        <option value="client">Client</option>
        <option value="tasker">Tasker</option>
        <option value="admin">Admin</option>
      </select>

      <button onClick={handleLogin}>Login</button>
    </div>
  );
}

const Client = () => <h2>Client Dashboard</h2>;
const Tasker = () => <h2>Tasker Dashboard</h2>;
const Admin = () => <h2>Admin Dashboard</h2>;

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />

          <Route element={<ProtectedRoute role="client" />}>
            <Route path="/client" element={<Client />} />
          </Route>

          <Route element={<ProtectedRoute role="tasker" />}>
            <Route path="/tasker" element={<Tasker />} />
          </Route>

          <Route element={<ProtectedRoute role="admin" />}>
            <Route path="/admin" element={<Admin />} />
          </Route>
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}
